export interface Payment {
  id: string;
  date: string; // YYYY-MM-DD
  amount: number;
  note: string;
}

export interface Fee {
  id: string;
  date: string;
  amount: number;
  description: string;
}

export interface Adjustment {
  id: string;
  date: string;
  amount: number; // Can be negative
  reason: string;
}

export interface MonthRecord {
  id: string; // Format: "YYYY-MM"
  year: number;
  month: number; // 1-12
  monthlyRent: number;
  dueDate: string; // YYYY-MM-DD
  payments: Payment[];
  manualFees: Fee[];
  adjustments: Adjustment[];
  // Calculated fields stored for caching or computed on fly
}

export interface PropertySettings {
  landlordName: string;
  landlordAddress: string;
  landlordEmail: string;
  tenantName: string;
  tenantAddress: string;
  tenantEmail: string;
  propertyAddress: string;
}

export interface AppData {
  settings: PropertySettings;
  records: MonthRecord[];
}

export interface MonthStats {
  totalRent: number;
  totalPayments: number;
  totalManualFees: number;
  totalAdjustments: number;
  flatLateFee: number;
  dailyLateFee: number;
  totalLateFees: number;
  totalOwed: number; // Rent + Fees + Adjustments - Payments (Technically "Remaining Balance" logic usually sums charges first)
  remainingBalance: number;
  isPaidOff: boolean;
  daysLate: number;
}

export const APP_STORAGE_KEY = 'rental-tracker-data-v1';

export const DEFAULT_SETTINGS = {
  landlordName: "John Doe Properties",
  landlordAddress: "123 Landlord Lane, Cityville, ST 12345",
  landlordEmail: "management@example.com",
  tenantName: "Jane Smith",
  tenantAddress: "Apt 4B, 456 Tenant Rd, Cityville, ST 12345",
  tenantEmail: "jane.smith@example.com",
  propertyAddress: "456 Tenant Rd, Apt 4B, Cityville, ST 12345"
};

export const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

import { MonthRecord, MonthStats } from '../types';
import { parseISO, differenceInCalendarDays, isAfter, isValid, startOfDay, addDays } from 'date-fns';

export const calculateMonthStats = (record: MonthRecord): MonthStats => {
  const { monthlyRent, dueDate, payments, manualFees, adjustments } = record;

  const totalPayments = payments.reduce((sum, p) => sum + p.amount, 0);
  const totalManualFees = manualFees.reduce((sum, f) => sum + f.amount, 0);
  const totalAdjustments = adjustments.reduce((sum, a) => sum + a.amount, 0);

  // --- Late Fee Logic ---
  let flatLateFee = 0;
  let dailyLateFee = 0;
  let daysLate = 0;

  const dueDateObj = parseISO(dueDate);
  const today = startOfDay(new Date());

  // Only calculate if due date is valid
  if (isValid(dueDateObj)) {
    // 1. Check for Flat Late Fee (10% of unpaid rent on day after due date)
    // Find payments made ON or BEFORE due date
    const paymentsByDueDate = payments
      .filter(p => !isAfter(parseISO(p.date), dueDateObj))
      .reduce((sum, p) => sum + p.amount, 0);

    const unpaidRentAtDueDate = Math.max(0, monthlyRent - paymentsByDueDate);

    // If unpaid rent exists and we are past the due date
    if (unpaidRentAtDueDate > 0 && isAfter(today, dueDateObj)) {
        flatLateFee = unpaidRentAtDueDate * 0.10;
    }

    // 2. Check for Daily Late Fee ($5/day)
    // Accrues for every day past due date where PRINCIPAL (Rent) is still unpaid.
    // It stops when principal is fully paid.

    // We need to walk through each day from DueDate + 1 until Today (or until paid off)
    // To do this accurately, we need to sort payments.

    const sortedPayments = [...payments].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    // Start checking from day after due date
    let currentCheckDate = addDays(dueDateObj, 1);

    // Only calculate up to today (we don't project future fees unless we want to, but standard is accrued)
    // Or, if fully paid, stop there.

    while (!isAfter(currentCheckDate, today)) {
      // Calculate payments made BEFORE or ON this check date
      const paymentsUntilNow = sortedPayments
        .filter(p => !isAfter(parseISO(p.date), currentCheckDate))
        .reduce((sum, p) => sum + p.amount, 0);

      const principalRemaining = Math.max(0, monthlyRent - paymentsUntilNow);

      if (principalRemaining > 0) {
        dailyLateFee += 5;
        daysLate++;
      } else {
        // Principal is paid off, stop accruing daily fees
        break; 
      }

      currentCheckDate = addDays(currentCheckDate, 1);
    }
  }

  const totalLateFees = flatLateFee + dailyLateFee;

  // Total Charges = Rent + Manual Fees + Late Fees + Adjustments (Adjustments can be negative)
  // Note: Adjustments usually reduce what is owed if negative, or add if positive.
  // We will assume 'amount' in adjustment is signed correctly.

  const totalCharges = monthlyRent + totalManualFees + totalLateFees + totalAdjustments;
  const remainingBalance = totalCharges - totalPayments;

  return {
    totalRent: monthlyRent,
    totalPayments,
    totalManualFees,
    totalAdjustments,
    flatLateFee,
    dailyLateFee,
    totalLateFees,
    totalOwed: totalCharges,
    remainingBalance,
    isPaidOff: remainingBalance <= 0,
    daysLate
  };
};

export const formatCurrency = (val: number) => {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(val);
};

export const formatDate = (dateStr: string) => {
    if(!dateStr) return '-';
    const date = parseISO(dateStr);
    return isValid(date) ? date.toLocaleDateString() : dateStr;
}

import { useState, useEffect } from 'react';
import { AppData, MonthRecord, Payment, Fee, Adjustment, PropertySettings } from '../types';
import { APP_STORAGE_KEY, DEFAULT_SETTINGS } from '../constants';
import { v4 as uuidv4 } from 'uuid'; // We'll implement a simple ID generator if uuid is not available, but let's assume simple random string for now to avoid dep
import { calculateMonthStats } from '../utils/calculations';

// Simple ID generator to avoid external dependency for this specific task
const generateId = () => Math.random().toString(36).substr(2, 9);

const INITIAL_DATA: AppData = {
  settings: DEFAULT_SETTINGS,
  records: []
};

export const useStore = () => {
  const [data, setData] = useState<AppData>(() => {
    const stored = localStorage.getItem(APP_STORAGE_KEY);
    return stored ? JSON.parse(stored) : INITIAL_DATA;
  });

  useEffect(() => {
    localStorage.setItem(APP_STORAGE_KEY, JSON.stringify(data));
  }, [data]);

  const updateSettings = (newSettings: PropertySettings) => {
    setData(prev => ({ ...prev, settings: newSettings }));
  };

  const addMonth = (year: number, month: number, rent: number, dueDate: string) => {
    const id = `${year}-${String(month).padStart(2, '0')}`;
    if (data.records.find(r => r.id === id)) {
      alert("Month already exists!");
      return;
    }
    const newRecord: MonthRecord = {
      id,
      year,
      month,
      monthlyRent: rent,
      dueDate,
      payments: [],
      manualFees: [],
      adjustments: []
    };
    setData(prev => ({
      ...prev,
      records: [...prev.records, newRecord].sort((a, b) => b.id.localeCompare(a.id))
    }));
  };

  const deleteMonth = (id: string) => {
    if(confirm("Are you sure you want to delete this month? All data will be lost.")){
        setData(prev => ({
            ...prev,
            records: prev.records.filter(r => r.id !== id)
        }));
    }
  };

  const updateMonthRent = (id: string, rent: number, dueDate: string) => {
      setData(prev => ({
          ...prev,
          records: prev.records.map(r => r.id === id ? { ...r, monthlyRent: rent, dueDate } : r)
      }));
  }

  // Generic helper to update a specific record
  const updateRecord = (monthId: string, updater: (record: MonthRecord) => MonthRecord) => {
    setData(prev => ({
      ...prev,
      records: prev.records.map(r => r.id === monthId ? updater(r) : r)
    }));
  };

  // --- Payment CRUD ---
  const addPayment = (monthId: string, payment: Omit<Payment, 'id'>) => {
    updateRecord(monthId, r => ({
      ...r,
      payments: [...r.payments, { ...payment, id: generateId() }]
    }));
  };
  const editPayment = (monthId: string, payment: Payment) => {
    updateRecord(monthId, r => ({
      ...r,
      payments: r.payments.map(p => p.id === payment.id ? payment : p)
    }));
  };
  const deletePayment = (monthId: string, paymentId: string) => {
    updateRecord(monthId, r => ({
      ...r,
      payments: r.payments.filter(p => p.id !== paymentId)
    }));
  };

  // --- Fee CRUD ---
  const addFee = (monthId: string, fee: Omit<Fee, 'id'>) => {
    updateRecord(monthId, r => ({
      ...r,
      manualFees: [...r.manualFees, { ...fee, id: generateId() }]
    }));
  };
  const editFee = (monthId: string, fee: Fee) => {
    updateRecord(monthId, r => ({
      ...r,
      manualFees: r.manualFees.map(f => f.id === fee.id ? fee : f)
    }));
  };
  const deleteFee = (monthId: string, feeId: string) => {
    updateRecord(monthId, r => ({
      ...r,
      manualFees: r.manualFees.filter(f => f.id !== feeId)
    }));
  };

  // --- Adjustment CRUD ---
  const addAdjustment = (monthId: string, adj: Omit<Adjustment, 'id'>) => {
    updateRecord(monthId, r => ({
      ...r,
      adjustments: [...r.adjustments, { ...adj, id: generateId() }]
    }));
  };
  const editAdjustment = (monthId: string, adj: Adjustment) => {
    updateRecord(monthId, r => ({
      ...r,
      adjustments: r.adjustments.map(a => a.id === adj.id ? adj : a)
    }));
  };
  const deleteAdjustment = (monthId: string, adjId: string) => {
    updateRecord(monthId, r => ({
      ...r,
      adjustments: r.adjustments.filter(a => a.id !== adjId)
    }));
  };

  const getMonth = (id: string) => data.records.find(r => r.id === id);

  return {
    data,
    updateSettings,
    addMonth,
    deleteMonth,
    updateMonthRent,
    addPayment,
    editPayment,
    deletePayment,
    addFee,
    editFee,
    deleteFee,
    addAdjustment,
    editAdjustment,
    deleteAdjustment,
    getMonth
  };
};

