export const MonthDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { getMonth, deleteMonth, updateMonthRent, addPayment, deletePayment, addFee, deleteFee, addAdjustment, deleteAdjustment } = useStore();

  const record = getMonth(id || '');

  // Form States
  const [modalType, setModalType] = useState<'payment' | 'fee' | 'adjustment' | 'editRent' | null>(null);

  // Payment Form
  const [payAmount, setPayAmount] = useState('');
  const [payDate, setPayDate] = useState('');
  const [payNote, setPayNote] = useState('');

  // Fee Form
  const [feeAmount, setFeeAmount] = useState('');
  const [feeDate, setFeeDate] = useState('');
  const [feeDesc, setFeeDesc] = useState('');

  // Adjustment Form
  const [adjAmount, setAdjAmount] = useState('');
  const [adjDate, setAdjDate] = useState('');
  const [adjReason, setAdjReason] = useState('');

  // Edit Rent Form
  const [editRentAmount, setEditRentAmount] = useState(0);
