  const stats = useMemo(() => record ? calculateMonthStats(record) : null, [record]);

  if (!record || !stats) return <div className="p-8">Record not found</div>;

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="bg-gray-100 min-h-screen p-4 md:p-8">
