             <span>Back to Details</span>
          </Link>
          <button 
            onClick={handlePrint}
            className="flex items-center space-x-2 bg-blue-600 text-white px-4 py-2 rounded shadow hover:bg-blue-700"
          >
             <Printer size={18} />
             <span>Print / Save as PDF</span>
          </button>
