export const MonthDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { getMonth, deleteMonth, updateMonthRent, addPayment, deletePayment, addFee, deleteFee, addAdjustment, deleteAdjustment } = useStore();

