        <div className="space-y-4">
            <div className="flex justify-between items-center">
                <h2 className="text-lg font-bold text-gray-900">Payments</h2>
                <button onClick={() => setModalType('payment')} className="text-sm bg-green-600 text-white px-3 py-1.5 rounded-lg hover:bg-green-700 flex items-center space-x-1">
                    <Plus size={14} /> <span>Add</span>
                </button>
            </div>
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
                <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                        <tr>
                            <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Date</th>
                            <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Note</th>
                            <th className="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase">Amount</th>
                            <th className="px-4 py-3 text-right"></th>
                        </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                        {record.payments.length === 0 ? (
                            <tr><td colSpan={4} className="px-4 py-4 text-center text-sm text-gray-500">No payments recorded</td></tr>
                        ) : (
                            record.payments.map(p => (
                                <tr key={p.id}>
                                    <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-900">{formatDate(p.date)}</td>
                                    <td className="px-4 py-3 text-sm text-gray-500">{p.note || '-'}</td>
                                    <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-900 text-right font-medium">{formatCurrency(p.amount)}</td>
                                    <td className="px-4 py-3 text-right">
                                        <button onClick={() => deletePayment(record.id, p.id)} className="text-red-400 hover:text-red-600"><Trash2 size={14} /></button>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>

        {/* Fees & Adjustments Section */}
        <div className="space-y-8">
             {/* Manual Fees */}
            <div className="space-y-4">
                <div className="flex justify-between items-center">
                    <h2 className="text-lg font-bold text-gray-900">Manual Fees</h2>
                    <button onClick={() => setModalType('fee')} className="text-sm bg-orange-500 text-white px-3 py-1.5 rounded-lg hover:bg-orange-600 flex items-center space-x-1">
                        <Plus size={14} /> <span>Add</span>
                    </button>
                </div>
                <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
                    <table className="min-w-full divide-y divide-gray-200">
                         <thead className="bg-gray-50">
                            <tr>
                                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Date</th>
                                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Desc</th>
                                <th className="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase">Amount</th>
                                <th className="px-4 py-3 text-right"></th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {record.manualFees.length === 0 ? (
                                <tr><td colSpan={4} className="px-4 py-4 text-center text-sm text-gray-500">No manual fees</td></tr>
                            ) : (
                                record.manualFees.map(f => (
                                    <tr key={f.id}>
                                        <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-900">{formatDate(f.date)}</td>
                                        <td className="px-4 py-3 text-sm text-gray-500">{f.description}</td>
                                        <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-900 text-right">{formatCurrency(f.amount)}</td>
                                        <td className="px-4 py-3 text-right">
                                            <button onClick={() => deleteFee(record.id, f.id)} className="text-red-400 hover:text-red-600"><Trash2 size={14} /></button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

             {/* Adjustments */}
             <div className="space-y-4">
                <div className="flex justify-between items-center">
                    <h2 className="text-lg font-bold text-gray-900">Adjustments</h2>
                    <button onClick={() => setModalType('adjustment')} className="text-sm bg-gray-600 text-white px-3 py-1.5 rounded-lg hover:bg-gray-700 flex items-center space-x-1">
                        <Plus size={14} /> <span>Add</span>
                    </button>
                </div>
                <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
                    <table className="min-w-full divide-y divide-gray-200">
                         <thead className="bg-gray-50">
                            <tr>
                                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Date</th>
                                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Reason</th>
                                <th className="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase">Amount</th>
                                <th className="px-4 py-3 text-right"></th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {record.adjustments.length === 0 ? (
                                <tr><td colSpan={4} className="px-4 py-4 text-center text-sm text-gray-500">No adjustments</td></tr>
                            ) : (
                                record.adjustments.map(a => (
                                    <tr key={a.id}>
                                        <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-900">{formatDate(a.date)}</td>
                                        <td className="px-4 py-3 text-sm text-gray-500">{a.reason}</td>
                                        <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-900 text-right">{formatCurrency(a.amount)}</td>
                                        <td className="px-4 py-3 text-right">
                                            <button onClick={() => deleteAdjustment(record.id, a.id)} className="text-red-400 hover:text-red-600"><Trash2 size={14} /></button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

      </div>

      {/* Modals */}
      <Modal isOpen={modalType === 'payment'} onClose={() => setModalType(null)} title="Record Payment">
         <form onSubmit={handleAddPayment} className="space-y-3">
             <input type="date" required value={payDate} onChange={e => setPayDate(e.target.value)} className="w-full border p-2 rounded" placeholder="Date" />
             <input type="number" step="0.01" required value={payAmount} onChange={e => setPayAmount(e.target.value)} className="w-full border p-2 rounded" placeholder="Amount ($)" />
             <input type="text" value={payNote} onChange={e => setPayNote(e.target.value)} className="w-full border p-2 rounded" placeholder="Note (e.g. Check #123)" />
             <button type="submit" className="w-full bg-green-600 text-white p-2 rounded hover:bg-green-700">Add Payment</button>
         </form>
      </Modal>

      <Modal isOpen={modalType === 'fee'} onClose={() => setModalType(null)} title="Add Manual Fee">
         <form onSubmit={handleAddFee} className="space-y-3">
             <input type="date" required value={feeDate} onChange={e => setFeeDate(e.target.value)} className="w-full border p-2 rounded" />
             <input type="number" step="0.01" required value={feeAmount} onChange={e => setFeeAmount(e.target.value)} className="w-full border p-2 rounded" placeholder="Amount ($)" />
             <input type="text" required value={feeDesc} onChange={e => setFeeDesc(e.target.value)} className="w-full border p-2 rounded" placeholder="Description (e.g. Eviction Fee)" />
             <button type="submit" className="w-full bg-orange-600 text-white p-2 rounded hover:bg-orange-700">Add Fee</button>
         </form>
      </Modal>

      <Modal isOpen={modalType === 'adjustment'} onClose={() => setModalType(null)} title="Add Adjustment">
         <form onSubmit={handleAddAdj} className="space-y-3">
             <input type="date" required value={adjDate} onChange={e => setAdjDate(e.target.value)} className="w-full border p-2 rounded" />
             <input type="number" step="0.01" required value={adjAmount} onChange={e => setAdjAmount(e.target.value)} className="w-full border p-2 rounded" placeholder="Amount ($) - Negative for credit" />
             <input type="text" required value={adjReason} onChange={e => setAdjReason(e.target.value)} className="w-full border p-2 rounded" placeholder="Reason" />
             <button type="submit" className="w-full bg-gray-600 text-white p-2 rounded hover:bg-gray-700">Add Adjustment</button>
         </form>
      </Modal>

      <Modal isOpen={modalType === 'editRent'} onClose={() => setModalType(null)} title="Edit Monthly Rent">
         <form onSubmit={handleRentUpdate} className="space-y-3">
             <div>
                <label className="text-xs text-gray-500">Rent Amount</label>
                <input type="number" step="0.01" required value={editRentAmount} onChange={e => setEditRentAmount(parseFloat(e.target.value))} className="w-full border p-2 rounded" />
             </div>
             <div>
                <label className="text-xs text-gray-500">Due Date</label>
                <input type="date" required value={editDueDate} onChange={e => setEditDueDate(e.target.value)} className="w-full border p-2 rounded" />
             </div>
             <div className="bg-yellow-50 text-yellow-800 p-2 text-xs rounded">
                Warning: Changing dates may affect calculated late fees.
             </div>
             <button type="submit" className="w-full bg-blue-600 text-white p-2 rounded hover:bg-blue-700">Update Rent</button>
         </form>
      </Modal>

    </div>
  );
};

import React, { useMemo } from 'react';
import { useParams, Link } from 'react-router-dom';
import { useStore } from '../hooks/useStore';
import { calculateMonthStats, formatCurrency, formatDate } from '../utils/calculations';
import { MONTH_NAMES } from '../constants';
import { ArrowLeft, Printer } from 'lucide-react';

export const Statement: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { getMonth, data } = useStore();
  const settings = data.settings;

  const record = getMonth(id || '');
  const stats = useMemo(() => record ? calculateMonthStats(record) : null, [record]);

  if (!record || !stats) return <div className="p-8">Record not found</div>;

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="bg-gray-100 min-h-screen p-4 md:p-8">
       {/* Actions Bar - Hidden on Print */}
       <div className="max-w-3xl mx-auto mb-6 flex justify-between items-center no-print">
          <Link to={`/month/${record.id}`} className="flex items-center space-x-2 text-gray-600 hover:text-gray-900">
             <ArrowLeft size={20} />
             <span>Back to Details</span>
          </Link>
          <button 
            onClick={handlePrint}
            className="flex items-center space-x-2 bg-blue-600 text-white px-4 py-2 rounded shadow hover:bg-blue-700"
          >
             <Printer size={18} />
             <span>Print / Save as PDF</span>
          </button>
       </div>

       {/* Statement Sheet - A4 styling approximation */}
       <div className="max-w-3xl mx-auto bg-white p-8 md:p-12 shadow-lg print:shadow-none print:w-full print:max-w-none print:p-0" id="statement-content">

          {/* Header */}
          <div className="flex justify-between items-start border-b border-gray-200 pb-8 mb-8">
              <div>
                  <h1 className="text-3xl font-bold text-gray-900">RENT STATEMENT</h1>
                  <p className="text-gray-500 mt-1">
                      Period: {MONTH_NAMES[record.month - 1]} {record.year}
                  </p>
                  <p className="text-sm text-gray-400 mt-4">Statement Date: {new Date().toLocaleDateString()}</p>
              </div>
              <div className="text-right">
                  <h2 className="font-bold text-lg">{settings.landlordName}</h2>
                  <div className="text-sm text-gray-600 whitespace-pre-line">{settings.landlordAddress}</div>
                  <div className="text-sm text-blue-600 mt-1">{settings.landlordEmail}</div>
              </div>
          </div>

          {/* Addresses */}
          <div className="grid grid-cols-2 gap-8 mb-8">
             <div>
                <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Tenant</h3>
                <div className="font-semibold">{settings.tenantName}</div>
                <div className="text-sm text-gray-600 whitespace-pre-line">{settings.tenantAddress}</div>
                <div className="text-sm text-gray-500 mt-1">{settings.tenantEmail}</div>
             </div>
             <div>
                <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Property</h3>
                <div className="text-sm text-gray-600">{settings.propertyAddress}</div>
             </div>
          </div>

          {/* Line Items */}
          <table className="w-full mb-8">
              <thead>
                  <tr className="border-b-2 border-gray-800">
                      <th className="text-left py-2 font-bold text-gray-800">Description</th>
                      <th className="text-left py-2 font-bold text-gray-800">Date</th>
                      <th className="text-right py-2 font-bold text-gray-800">Amount</th>
                  </tr>
              </thead>
              <tbody className="divide-y divide-gray-200 text-sm">
                  {/* Rent */}
                  <tr>
                      <td className="py-3">Monthly Rent</td>
                      <td className="py-3">{formatDate(record.dueDate)} (Due)</td>
                      <td className="py-3 text-right">{formatCurrency(record.monthlyRent)}</td>
                  </tr>

                  {/* Manual Fees */}
                  {record.manualFees.map((fee, i) => (
                      <tr key={`fee-${i}`}>
                          <td className="py-3">{fee.description}</td>
                          <td className="py-3">{formatDate(fee.date)}</td>
                          <td className="py-3 text-right">{formatCurrency(fee.amount)}</td>
                      </tr>
                  ))}

                  {/* Adjustments */}
                  {record.adjustments.map((adj, i) => (
                      <tr key={`adj-${i}`}>
                          <td className="py-3">Adjustment: {adj.reason}</td>
                          <td className="py-3">{formatDate(adj.date)}</td>
                          <td className="py-3 text-right">{formatCurrency(adj.amount)}</td>
                      </tr>
                  ))}

                  {/* Late Fees */}
                  {stats.flatLateFee > 0 && (
                      <tr>
                          <td className="py-3 text-red-600">Late Fee (Flat 10%)</td>
                          <td className="py-3">-</td>
                          <td className="py-3 text-right text-red-600">{formatCurrency(stats.flatLateFee)}</td>
                      </tr>
                  )}
                  {stats.dailyLateFee > 0 && (
                      <tr>
                          <td className="py-3 text-red-600">Daily Late Fees ({stats.daysLate} days @ $5)</td>
                          <td className="py-3">-</td>
                          <td className="py-3 text-right text-red-600">{formatCurrency(stats.dailyLateFee)}</td>
                      </tr>
                  )}
              </tbody>
          </table>

          {/* Totals Section */}
          <div className="flex justify-end mb-8">
              <div className="w-1/2 space-y-2">
                  <div className="flex justify-between py-1 border-b border-gray-100">
                      <span className="text-gray-600">Total Charges</span>
                      <span className="font-semibold">{formatCurrency(stats.totalOwed)}</span>
                  </div>
                  <div className="flex justify-between py-1 border-b border-gray-100">
                      <span className="text-gray-600">Payments Received</span>
                      <span className="font-semibold text-green-600">-{formatCurrency(stats.totalPayments)}</span>
                  </div>
                  <div className="flex justify-between py-3 border-t-2 border-gray-800 text-lg">
                      <span className="font-bold">Amount Due</span>
                      <span className={`font-bold ${stats.remainingBalance > 0 ? 'text-red-600' : 'text-gray-800'}`}>
                          {formatCurrency(stats.remainingBalance)}
                      </span>
                  </div>
              </div>
          </div>

          {/* Payment History List (For reference) */}
          {record.payments.length > 0 && (
              <div className="mt-8 pt-8 border-t border-gray-200">
                  <h4 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-4">Payment History</h4>
                  <div className="bg-gray-50 rounded p-4">
                      <table className="w-full text-sm">
                          <tbody>
                              {record.payments.map((p, i) => (
                                  <tr key={`ph-${i}`}>
                                      <td className="py-1 w-1/4">{formatDate(p.date)}</td>
                                      <td className="py-1 w-1/2 text-gray-500 italic">{p.note}</td>
                                      <td className="py-1 w-1/4 text-right">{formatCurrency(p.amount)}</td>
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
              </div>
          )}

          <div className="mt-12 text-center text-xs text-gray-400">
              Generated by Rental Property Tracker
          </div>

       </div>
    </div>
  );
};
